const body = $json.body || $json;

let strategy = "Maintain momentum";
let urgency = "normal";
let actionType = "follow-up";

const days = body.days_since_contact || 0;

if (days >= 10) {
  strategy = "Re-engage relationship";
  urgency = "high";
}

if (days >= 5 && days < 10) {
  strategy = "Encourage response";
  urgency = "medium";
}

if (days < 5) {
  strategy = "Maintain active conversation";
  urgency = "low";
}

return [{
  json: {
    user_id: body.user_id,
    client_id: body.client_id,
    client_name: body.client_name,
    client_email: body.client_email,

    notes: body.notes || "",
    tags: body.tags || [],

    last_outreach: body.last_outreach || "",
    days_since_contact: days,

    relationship_status: body.relationship_status || "",
    outreach_tone: body.tone || "professional",

    outreach_strategy: strategy,
    outreach_urgency: urgency,

    action_type: actionType
  }
}];

const raw = $json.output || $json.text || "";

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (err) {
  parsed = {
    subject: "Follow Up",
    body: raw,
    cta: "",
    confidence_score: 0.75
  };
}

const cleanBody = parsed.body
  ?.replace(/\\n/g, '\n')
  ?.replace(/\n{3,}/g, '\n\n')
  ?.trim();

item.json.clean_draft = {
  subject: parsed.subject || "Follow Up",
  body: cleanBody || "",
  cta: parsed.cta || "",
  confidence_score: parsed.confidence_score || 0.75
};

return item;

